import java.io.*;
import java.nio.charset.*;
public class App {
    public static void main(String[] args) throws Exception {
        String response = "HTTP/1.1 200 OK\nContent-Type: application/json\n\n{\"id\": 1}\n{\"id\": 2}\n{\"id\": 3}";
        byte[] responseBytes = response.getBytes(StandardCharsets.UTF_8);
        InputStream stream = new ByteArrayInputStream(responseBytes);

        int headerLines = 0, bodyLines = 0;
        String status = null;
        String contentType = null;
        boolean inBody = false;

        try (BufferedReader br = new BufferedReader(
                new InputStreamReader(stream, StandardCharsets.UTF_8))) {
            String line;
            while ((line = br.readLine()) != null) {
                if (line.startsWith("HTTP")) { status = line.substring(9); }
                else if (line.startsWith("Content-Type")) { contentType = line.substring(14); }
                else if (line.isEmpty()) { inBody = true; }
                else if (inBody) { bodyLines++; }
            }
        }
        System.out.println("Status: " + status);
        System.out.println("Content-Type: " + contentType);
        System.out.println("Body lines: " + bodyLines);
    }
}

