import java.io.*;
import java.nio.file.*;
class Logger {
    private final Path logFile;
    private final long maxSize;
    Logger(Path p, long maxBytes) throws IOException {
        logFile = p;
        maxSize = maxBytes;
        if (!Files.exists(p)) Files.createFile(p);
    }
    void log(String level, String message) throws IOException {
        String entry = level + " " + message + "\n";
        try (BufferedWriter bw = new BufferedWriter(
                new FileWriter(logFile.toFile(), true))) {  // append=true
            bw.write(entry);
        }
        System.out.println("Logged: " + level + " " + message);
        if (Files.size(logFile) > maxSize) {
            System.out.println("Log rotation needed (size: " + Files.size(logFile) + " bytes)");
        }
    }
}
public class App {
    public static void main(String[] args) throws Exception {
        Logger logger = new Logger(Path.of("app.log"), 200);
        logger.log("INFO",  "app started");
        logger.log("INFO",  "processing order ORD-001");
        logger.log("WARN",  "response time 450ms");
        logger.log("ERROR", "payment failed for user-42");
    }
}

