import java.io.*;
record Holding(String symbol, int shares, double avgCost, double curPrice) {
    double pnlPct() { return (curPrice / avgCost - 1) * 100; }
}
public class App {
    public static void main(String[] args) throws Exception {
        Holding[] h = {
            new Holding("RELIANCE", 20, 2197, 2450),
            new Holding("TCS",      10, 2760, 3890),
            new Holding("INFY",     30, 1600, 1560)
