            pw.println("=== Portfolio Report ===");
            pw.printf("%-10s %6s  %8s  %9s  %5s%n",
                "Symbol", "Shares", "Avg Cost", "Cur Price", "P&L%");
            pw.println("-".repeat(46));
            for (Holding holding : h) {
                pw.printf("%-10s %6d  ₹%6.0f   ₹%6.0f   %+.1f%%%n",
                    holding.symbol(), holding.shares(),
                    holding.avgCost(), holding.curPrice(), holding.pnlPct());
            }
        }
        System.out.print(sw);
    }
}

