import java.io.*;
import java.nio.file.*;
public class App {
    public static void main(String[] args) throws Exception {
        Path src = Path.of("employees.csv");
        Files.writeString(src,
            "# Employee data\n" +
            "id,name,dept\n" +
            "1,Aisha,Engineering\n" +
            "2,Raj,Sales\n" +
            "\n" +
            "# More data\n" +
            "3,Priya,Engineering\n" +
            "4,Vikram,Marketing\n" +
            "5,Anita,Sales");

        Path out = Path.of("employees_out.csv");
        int count = 0;
        try (BufferedReader br = Files.newBufferedReader(src);
             PrintWriter pw = new PrintWriter(
                     new BufferedWriter(new FileWriter(out.toFile())))) {
            String line;
            while ((line = br.readLine()) != null) {
                if (line.isBlank() || line.startsWith("#")) continue;
                String[] cols = line.split(",");
                if (cols[0].equals("id")) { pw.println(line); continue; }  // header
                pw.printf("%s,%s,%s%n", cols[0], cols[1].toUpperCase(), cols[2]);
                count++;
            }
        }
        System.out.println("Transformed: " + count + " employees");
        System.out.println("Output written.");
    }
}

