import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws Exception {
        // Create 3 daily files
        String[] days = {"day1.csv","day2.csv","day3.csv"};
        Files.writeString(Path.of(days[0]), "P01,799\nP02,5000\nP03,1299");
        Files.writeString(Path.of(days[1]), "P01,799\nP02,5000\nP01,799");
        Files.writeString(Path.of(days[2]), "P02,5000\nP03,1299\nP01,799");

        Map<String, Integer> productCount = new HashMap<>();
        Map<String, Long>    productRevenue = new HashMap<>();
        long totalRevenue = 0;
        int  totalOrders  = 0;

        for (String day : days) {
            try (BufferedReader br = Files.newBufferedReader(Path.of(day))) {
                String line;
                while ((line = br.readLine()) != null) {
                    String[] cols = line.split(",");
                    String product = cols[0];
                    long amount    = Long.parseLong(cols[1]);
                    productCount.merge(product, 1, Integer::sum);
                    productRevenue.merge(product, amount, Long::sum);
                    totalRevenue += amount;
                    totalOrders++;
                }
            }
        }

        String topProduct = productCount.entrySet().stream()
            .max(Map.Entry.comparingByValue())
            .map(Map.Entry::getKey).orElse("none");

        StringWriter sw = new StringWriter();
        try (PrintWriter pw = new PrintWriter(sw)) {
            pw.println("=== Sales Aggregation Report ===");
            pw.println("Files processed: 3");
            pw.println("Total orders: " + totalOrders);
            pw.println("Total revenue: ₹" + totalRevenue);
            pw.println("Top product: " + topProduct + " (" + productCount.get(topProduct) + " orders)");
            pw.println("Top product revenue: ₹" + productRevenue.get(topProduct));
        }
        System.out.print(sw);
    }
}
